import React, { useState } from "react";
import {
  Container,
  Paper,
  Typography,
  TextField,
  Button,
  Snackbar,
  Alert,
} from "@mui/material";
import axios from "axios";

export default function RiderRegister() {
  const [form, setForm] = useState({ fullName: "", email: "", mobile: "", password: "" });
  const [loading, setLoading] = useState(false);
  const [popup, setPopup] = useState({ open: false, type: "success", message: "" });

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      const res = await axios.post("/api/auth/rider/register", form);
      setPopup({ open: true, type: "success", message: res.data.message });
      setForm({ fullName: "", email: "", mobile: "", password: "" });
    } catch (err) {
      const msg = err.response?.data?.message || "Server error. Try again.";
      setPopup({ open: true, type: "error", message: msg });
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="sm">
      <Paper sx={{ mt: 8, p: 4 }}>
        <Typography variant="h4" sx={{ mb: 2, fontWeight: "bold" }}>
          Rider Signup
        </Typography>
        <Typography variant="body2" sx={{ mb: 2 }}>
          Create your account and upload documents.
        </Typography>

        <form onSubmit={handleSubmit}>
          <TextField
            fullWidth
            label="Full Name"
            name="fullName"
            value={form.fullName}
            onChange={handleChange}
            margin="normal"
            required
          />
          <TextField
            fullWidth
            label="Email"
            name="email"
            type="email"
            value={form.email}
            onChange={handleChange}
            margin="normal"
            required
          />
          <TextField
            fullWidth
            label="Mobile Number"
            name="mobile"
            value={form.mobile}
            onChange={handleChange}
            margin="normal"
            required
          />
          <TextField
            fullWidth
            label="Password"
            name="password"
            type="password"
            value={form.password}
            onChange={handleChange}
            margin="normal"
            required
          />

          <Button
            type="submit"
            variant="contained"
            fullWidth
            disabled={loading}
            sx={{ mt: 3, bgcolor: "black", color: "white", "&:hover": { bgcolor: "#333" } }}
          >
            {loading ? "Registering..." : "Register"}
          </Button>
        </form>
      </Paper>

      {/* Popup Snackbar */}
      <Snackbar
        open={popup.open}
        autoHideDuration={4000}
        onClose={() => setPopup({ ...popup, open: false })}
      >
        <Alert
          onClose={() => setPopup({ ...popup, open: false })}
          severity={popup.type}
          variant="filled"
          sx={{ width: "100%" }}
        >
          {popup.message}
        </Alert>
      </Snackbar>
    </Container>
  );
}
